  ('pukao-7fec267e-moex-00442', 'pukao-7fec267e', 'pukao-7fec267e-moex-111-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '馬克思認為：「在每個時代中，統治階級的觀念就是主流的觀念」，這句話的意義，跟下列那個 概念最相關？', '["文化霸權", "公民文化", "激進民主", "政治社會化"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:15+00:00", "source_pdf_sha1": "dc929727d2e7", "answer_pdf_sha1": "ad6aca1f3dbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "401", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00443', 'pukao-7fec267e', 'pukao-7fec267e-moex-111-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '在政治場域中，有一種主張認為任何政治決策必須遵照人民的偏好才是對的，以及強調訴諸多數 人民的正當性，藉以對抗既有的法律規範。從負面效應來看，這樣的主張，容易以人民為號召， 最後權力卻落入帶領人民的少數菁英手上，甚至形成獨裁政權。這種主張被稱為：', '["民粹主義", "無政府主義", "放任自由主義", "憲政主義 40220"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:15+00:00", "source_pdf_sha1": "dc929727d2e7", "answer_pdf_sha1": "ad6aca1f3dbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "401", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00444', 'pukao-7fec267e', 'pukao-7fec267e-moex-111-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '關於政治意識型態，下列敘述何者正確？', '["政治意識型態與政治觀念（ideas）為同義之概念", "政治意識型態必然包含對理想政治生活的願景", "不同政治意識型態之間的關係必是敵對的", "政治意識型態對憲政國家皆是有害的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:15+00:00", "source_pdf_sha1": "dc929727d2e7", "answer_pdf_sha1": "ad6aca1f3dbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "401", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00445', 'pukao-7fec267e', 'pukao-7fec267e-moex-111-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '對公民不服從概念的敘述，下列何者錯誤？', '["通常是為了更高的宗教、道德或政治原則，違反法律的行為", "通常堅持避免暴力", "公民不服從是私下進行的違法行為", "公民不服從運動的知名倡導者包含甘地、梭羅與馬丁路德金恩"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:15+00:00", "source_pdf_sha1": "dc929727d2e7", "answer_pdf_sha1": "ad6aca1f3dbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "401", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00446', 'pukao-7fec267e', 'pukao-7fec267e-moex-111-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '政治參與可分慣常性與非慣常性兩種，下列那一種屬於後者？', '["投票與競選活動", "遊行示威", "向政治領導者表達支持或抗議訊息", "討論及批評政府作為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:15+00:00", "source_pdf_sha1": "dc929727d2e7", "answer_pdf_sha1": "ad6aca1f3dbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "401", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
